DESCRIPTION = '葬儀の規模・形式・地域を選ぶだけで葬儀費用の目安を無料シミュレーション。家族葬・一般葬・直葬の費用比較と終活の準備チェックリストを提供します。'
JS_CODE = 'const questions = [\n    {\n      id: \'style\',\n      text: \'希望する葬儀の形式を教えてください\',\n      options: [\'一般葬（親族・知人・会社関係者を招く）\', \'家族葬（家族・親しい人のみ）\', \'一日葬（通夜なし）\', \'直葬・火葬のみ\', \'まだ決めていない\']\n    },\n    {\n      id: \'attendance\',\n      text: \'予定される参列者数はどのくらいですか？\',\n      options: [\'10人未満\', \'10〜30人\', \'30〜80人\', \'80〜150人\', \'150人以上\']\n    },\n    {\n      id: \'region\',\n      text: \'お住まいの地域を教えてください\',\n      options: [\'東京・大阪・名古屋などの大都市\', \'地方の政令市・中規模都市\', \'郊外・地方都市\', \'農村・山間部・離島\']\n    },\n    {\n      id: \'religion\',\n      text: \'宗教・宗派はどちらですか？\',\n      options: [\'仏教（寺院・お坊さんへのお布施あり）\', \'キリスト教\', \'神道\', \'無宗教・自由葬\', \'分からない\']\n    },\n    {\n      id: \'cemetery\',\n      text: \'お墓・納骨の予定はありますか？\',\n      options: [\'既存のお墓がある\', \'これからお墓を建てる予定\', \'樹木葬・散骨を希望\', \'納骨堂・永代供養を希望\', \'まだ決めていない\']\n    },\n    {\n      id: \'insurance\',\n      text: \'葬儀費用のための貯蓄・保険はありますか？\',\n      options: [\'生命保険で300万円以上ある\', \'葬儀保険・互助会に加入済み\', \'預貯金で100〜300万円用意できる\', \'特に準備していない\']\n    },\n    {\n      id: \'preparation\',\n      text: \'終活の準備状況を教えてください\',\n      options: [\'エンディングノートを作成済み\', \'遺言書を作成済み\', \'家族と話し合い済み\', \'まだ何もしていない\']\n    }\n  ];\n\n  let currentStep = 0;\n  let answers = {};\n\n  function renderQuestion() {\n    const q = questions[currentStep];\n    document.getElementById(\'step-label\').textContent = `質問 ${currentStep + 1} / ${questions.length}`;\n    document.getElementById(\'progress-bar\').style.width = `${((currentStep + 1) / questions.length) * 100}%`;\n    document.getElementById(\'prev-btn\').classList.toggle(\'hidden\', currentStep === 0);\n    document.getElementById(\'next-btn\').textContent = currentStep === questions.length - 1 ? \'診断する\' : \'次へ\';\n\n    let html = `<p class="font-semibold text-gray-800 mb-4">${q.text}</p><div class="space-y-2">`;\n    q.options.forEach(opt => {\n      const checked = answers[q.id] === opt ? \'checked\' : \'\';\n      html += `<label class="flex items-center gap-3 p-3 border border-gray-200 rounded-xl cursor-pointer hover:border-slate-400 transition has-[:checked]:border-slate-500 has-[:checked]:bg-slate-50">\n        <input type="radio" name="${q.id}" value="${opt}" ${checked} class="accent-slate-600"> <span class="text-sm">${opt}</span>\n      </label>`;\n    });\n    html += \'</div>\';\n    document.getElementById(\'question-area\').innerHTML = html;\n  }\n\n  function saveAnswer() {\n    const el = document.querySelector(`input[name="${questions[currentStep].id}"]:checked`);\n    if (!el) { alert(\'選択してください\'); return false; }\n    answers[questions[currentStep].id] = el.value;\n    return true;\n  }\n\n  function nextStep() {\n    if (!saveAnswer()) return;\n    if (currentStep < questions.length - 1) { currentStep++; renderQuestion(); }\n    else showResult();\n  }\n\n  function prevStep() {\n    if (currentStep > 0) { currentStep--; renderQuestion(); }\n  }\n\n  function calcCost() {\n    let baseCost = 0;\n    const styleMap = {\n      \'一般葬（親族・知人・会社関係者を招く）\': 150,\n      \'家族葬（家族・親しい人のみ）\': 60,\n      \'一日葬（通夜なし）\': 40,\n      \'直葬・火葬のみ\': 15,\n      \'まだ決めていない\': 80\n    };\n    baseCost = styleMap[answers.style] || 80;\n\n    const attendanceAdd = {\n      \'10人未満\': 0, \'10〜30人\': 10, \'30〜80人\': 30,\n      \'80〜150人\': 60, \'150人以上\': 100\n    };\n    baseCost += attendanceAdd[answers.attendance] || 0;\n\n    const regionMult = {\n      \'東京・大阪・名古屋などの大都市\': 1.3,\n      \'地方の政令市・中規模都市\': 1.0,\n      \'郊外・地方都市\': 0.9,\n      \'農村・山間部・離島\': 0.85\n    };\n    baseCost = Math.round(baseCost * (regionMult[answers.region] || 1.0));\n\n    if (answers.religion === \'仏教（寺院・お坊さんへのお布施あり）\') baseCost += 30;\n\n    let cemeteryAdd = 0;\n    if (answers.cemetery === \'これからお墓を建てる予定\') cemeteryAdd = 150;\n    else if (answers.cemetery === \'納骨堂・永代供養を希望\') cemeteryAdd = 50;\n    else if (answers.cemetery === \'樹木葬・散骨を希望\') cemeteryAdd = 20;\n\n    return { funeralCost: baseCost, cemeteryAdd };\n  }\n\n  function showResult() {\n    document.getElementById(\'quiz-section\').classList.add(\'hidden\');\n    document.getElementById(\'result-section\').classList.remove(\'hidden\');\n\n    const { funeralCost, cemeteryAdd } = calcCost();\n    const totalCost = funeralCost + cemeteryAdd;\n    const isUnprepared = answers.preparation '
